			sbuf_mem(freedsb, &hist[i].mark, (int)sizeof(void*))
			lopt_done(&hist[i]);
			skip:;
		}
		ptr += n * sizeof(lb->hist[0]) + sizeof(n);
	}
	sbuf_free(lb->rehist)
	sbuf_free(freedsb)
}

